const i=`{% block sw_plugin_box %} <div class="sw-plugin-box"> {% block sw_plugin_box_container %} <sw-container columns="3fr 1fr" gap="0px 30px" class="sw-plugin-box__container" > {% block sw_plugin_box_container_plugin_data %} <sw-container :class="{ 'has--no-icon' : !plugin.icon }"> {% block sw_plugin_box_container_plugin_data_icon %} <img v-if="!!plugin.icon" class="sw-plugin-box__icon" :src="\`data:image/png;base64, \${plugin.icon}\`" alt="" > {% endblock %} {% block sw_plugin_box_container_plugin_data_description %} <div class="sw-plugin-box__description"> {% block sw_plugin_box_container_plugin_data_description_label %} <p class="sw-plugin-box__label"> {{ plugin.translated?.label }} </p> {% endblock %} {% block sw_plugin_box_container_plugin_data_description_author %} <p class="sw-plugin-box__author"> {{ plugin.author }} </p> {% endblock %} </div> {% endblock %} </sw-container> {% endblock %} {% block sw_plugin_box_container_button %} <mt-button v-if="hasPluginConfig" ghost size="small" class="sw-plugin-box__button" variant="secondary" @click="$router.push({ name: 'sw.extension.config', params: { namespace: plugin.name } })" > {{ $t('sw-plugin-box.buttonPluginSettings') }} </mt-button> {% endblock %} </sw-container> {% endblock %} </div> {% endblock %}`,o={template:i,inject:["systemConfigApiService","repositoryFactory"],props:{pluginId:{type:String,required:!0}},data(){return{plugin:{},hasPluginConfig:!1}},computed:{pluginRepository(){return this.repositoryFactory.create("plugin")}},watch:{"plugin.name":{handler(){!this.plugin.name||this.hasPluginConfig||this.checkPluginConfig()}}},created(){this.createdComponent()},methods:{createdComponent(){this.pluginRepository.get(this.pluginId).then(n=>{this.plugin=n})},checkPluginConfig(){this.systemConfigApiService.checkConfig(`${this.plugin.name}.config`).then(n=>{this.hasPluginConfig=n}).catch(()=>{this.hasPluginConfig=!1})}}};export{o as default};
